import type Color from "../../../Color.js";
import type { JSONSupport } from "../../../core/JSONSupport.js";
import type { ColorLike } from "../../../Color.js";

export interface ColorSizeStopProperties extends Partial<Pick<ColorSizeStop, "label" | "value">> {
  /** The [Color](https://developers.arcgis.com/javascript/latest/references/core/Color/) used to render features with the given [value](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/support/ColorSizeStop/#value). */
  color?: ColorLike;
  /**
   * The size value in points used to render features with the given [value](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/support/ColorSizeStop/#value).
   * This value may also be autocast from a string in points or pixels.
   */
  size?: number | string;
}

/**
 * Defines how to data values should be represented in the [ColorSizeSlider](https://developers.arcgis.com/javascript/latest/references/core/widgets/smartMapping/ColorSizeSlider/) with an associated color and size.
 *
 * @since 4.12
 * @see [ColorSizeSlider.stops](https://developers.arcgis.com/javascript/latest/references/core/widgets/smartMapping/ColorSizeSlider/#stops)
 */
export default class ColorSizeStop extends JSONSupport {
  constructor(properties?: ColorSizeStopProperties);
  /** The [Color](https://developers.arcgis.com/javascript/latest/references/core/Color/) used to render features with the given [value](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/support/ColorSizeStop/#value). */
  get color(): Color;
  set color(value: ColorLike);
  /** A string value used to label the stop in the [Legend](https://developers.arcgis.com/javascript/latest/references/map-components/components/arcgis-legend/). */
  accessor label: string | null | undefined;
  /**
   * The size value in points used to render features with the given [value](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/support/ColorSizeStop/#value).
   * This value may also be autocast from a string in points or pixels.
   */
  get size(): number;
  set size(value: number | string);
  /** Specifies the data value to map to the given [size](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/support/ColorSizeStop/#size) and [color](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/support/ColorSizeStop/#color). */
  accessor value: number;
  /**
   * Creates a deep clone of the ColorSizeStop.
   *
   * @returns A deep clone of the size
   *   stop that invoked this method.
   * @example
   * // Creates a deep clone of the visual variable
   * const stops = renderer.visualVariables[0].stops.map(function(stop){
   *   return stop.clone();
   * });
   */
  clone(): ColorSizeStop;
}